export interface JobStatus {
  id: string;
  state: "queued" | "running" | "done" | "failed";
}

export interface JobGateway {
  fetchStatus(id: string): Promise<JobStatus>;
}

export class JobDetailPanel {
  private status: JobStatus | null = null;
  private latestRequest = 0;

  constructor(private readonly gateway: JobGateway) {}

  async select(jobId: string): Promise<void> {
    const requestId = ++this.latestRequest;
    const result = await this.gateway.fetchStatus(jobId);
    if (requestId !== this.latestRequest) {
      return;
    }
    this.status = result;
  }

  current(): JobStatus | null {
    return this.status;
  }
}

